154.4 Solve the Problem

clinic_files &lt;- c(
  list.files("data/clinics", pattern = "\\.csv$", full.names = TRUE),
  "data/clinics/clinic_nonexistent.csv"   # deliberately broken path
)

safe_read_csv &lt;- function(path) {
  tryCatch({
    read.csv(path)
  }, error = function(e) {
    cat("Skipping", path, "-", conditionMessage(e), "\n")
    NULL
  })
}

all_results &lt;- vector("list", length(clinic_files))
for (i in seq_along(clinic_files)) {
  all_results[[i]] &lt;- safe_read_csv(clinic_files[i])
}

successful_results &lt;- all_results[!sapply(all_results, is.null)]
length(successful_results)

Skipping data/clinics/clinic_nonexistent.csv - cannot open the connection
[1] 5

combined &lt;- do.call(rbind, successful_results)
nrow(combined)

[1] 100
The broken file path printed a clear message and was skipped — all_results still contains NULL in its place — while the 5 genuine clinic files were read successfully and combined into the same 100-row dataset Level 10’s capstone reconstructed, exactly as if the broken path had never been in the list.

161.1 The R Concept
This capstone’s function combines four separate ideas from across this level into one:
read_clinic_folder &lt;- function(folder_path) {
  csv_files &lt;- list.files(folder_path, pattern = "\\.csv$", full.names = TRUE)  # Page 7 (regex)

  results &lt;- vector("list", length(csv_files))
  failed &lt;- character(0)

  for (i in seq_along(csv_files)) {
    results[[i]] &lt;- tryCatch({                    # Page 4 (error handling)
      read.csv(csv_files[i])
    }, error = function(e) {
      failed &lt;&lt;- c(failed, csv_files[i])
      NULL
    })
  }

  successful &lt;- results[!sapply(results, is.null)]

  structure(list(                                  # Page 3 (S3 object)
    data = do.call(rbind, successful),
    n_files_found = length(csv_files),
    n_files_read = length(successful),
    failed_files = failed
  ), class = "clinic_batch")
}

print.clinic_batch &lt;- function(x, ...) {
  cat(sprintf("Clinic batch: %d/%d files read successfully (%d rows total)\n",
              x$n_files_read, x$n_files_found, nrow(x$data)))
  if (length(x$failed_files) &gt; 0) {
    cat("Failed files:", paste(x$failed_files, collapse = ", "), "\n")
  }
}

161.4 Solve the Problem

read_clinic_folder &lt;- function(folder_path) {
  csv_files &lt;- list.files(folder_path, pattern = "\\.csv$", full.names = TRUE)

  results &lt;- vector("list", length(csv_files))
  failed &lt;- character(0)

  for (i in seq_along(csv_files)) {
    results[[i]] &lt;- tryCatch({
      read.csv(csv_files[i])
    }, error = function(e) {
      failed &lt;&lt;- c(failed, csv_files[i])
      NULL
    })
  }

  successful &lt;- results[!sapply(results, is.null)]

  structure(list(
    data = do.call(rbind, successful),
    n_files_found = length(csv_files),
    n_files_read = length(successful),
    failed_files = failed
  ), class = "clinic_batch")
}

print.clinic_batch &lt;- function(x, ...) {
  cat(sprintf("Clinic batch: %d/%d files read successfully (%d rows total)\n",
              x$n_files_read, x$n_files_found, nrow(x$data)))
  if (length(x$failed_files) &gt; 0) {
    cat("Failed files:", paste(x$failed_files, collapse = ", "), "\n")
  }
}

batch &lt;- read_clinic_folder("data/clinics")

nrow(batch$data)
batch$n_files_read

[1] 100
[1] 5

table(batch$data$county)


Cedar Falls    Millbrook      Oakford    Riverdale   Springvale
         20           21           17           16           26
All 5 clinic files were found (via the same "\\.csv$" regex pattern from Page 7) and successfully read (using tryCatch()-wrapped reads from Page 4), producing the identical 100-row combined dataset and county breakdown that Level 10’s capstone reconstructed — but this version, unlike Level 10’s, would have survived a missing or corrupted file, reporting it in failed_files instead of crashing.

